async (params, browser) => {
  // Open Discord channel
  await browser.open(`${params.channel_url}`)

  // Wait for messages to load
  await browser.waitForSelector('ol[data-list-id=\'chat-messages\']', 15000)

  // Let messages render
  await browser.wait(2000)

  // Extract messages
  const channel_messages = await browser.evaluate(`const messages = []; const chatList = document.querySelector('ol[data-list-id="chat-messages"]'); if (!chatList) return { message_count: 0, channel_url: window.location.href, messages: [] }; const msgEls = chatList.querySelectorAll('li[id^="chat-messages-"]'); for (let i = Math.max(0, msgEls.length - 20); i < msgEls.length; i++) { const el = msgEls[i]; const headerEl = el.querySelector('h3'); const authorEl = headerEl ? headerEl.querySelector('span[id^="message-username-"]') : null; const contentEl = el.querySelector('div[id^="message-content-"]'); const timeEl = el.querySelector('time'); if (contentEl && contentEl.textContent.trim()) { messages.push({ author: authorEl ? authorEl.textContent.trim() : '', content: contentEl.textContent.trim(), timestamp: timeEl ? timeEl.getAttribute('datetime') || timeEl.textContent.trim() : '' }); } } return { message_count: messages.length, channel_url: window.location.href, messages: messages }`)

  return channel_messages
}
